import{_ as t,o as r,c as o,a2 as l}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"F17: 籌碼分佈與法人動態分析 - 財務審計專家 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/3036_文曄/20260512/F17_籌碼分佈與法人動態分析.md","filePath":"審計報告庫/財務審計/3036_文曄/20260512/F17_籌碼分佈與法人動態分析.md"}'),i={name:"審計報告庫/財務審計/3036_文曄/20260512/F17_籌碼分佈與法人動態分析.md"};function n(e,a,s,h,d,g){return r(),o("div",null,[...a[0]||(a[0]=[l('<h1 id="f17-籌碼分佈與法人動態分析-財務審計專家-審計報告" tabindex="-1">F17: 籌碼分佈與法人動態分析 - 財務審計專家 審計報告 <a class="header-anchor" href="#f17-籌碼分佈與法人動態分析-財務審計專家-審計報告" aria-label="Permalink to &quot;F17: 籌碼分佈與法人動態分析 - 財務審計專家 審計報告&quot;">​</a></h1><blockquote><p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的財務洞見。</p></blockquote><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>外資、投信與自營商的近期買賣超動向為何？千張大戶持股比例是否發生結構性變化？</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li><strong>核心結論</strong>：外資近4日累計買超2,219萬股強勢布局，投信同步買超348萬股。法人共識性買盤明確。</li><li><strong>風險評級</strong>：低</li><li><strong>數據時效</strong>：截至2026年5月</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><ul><li><strong>法人買賣超(近4日)</strong>：外資+2,219萬股(5/7: +1,195萬; 5/8: +170萬; 5/11: +855萬)。投信+348萬股。自營商+30萬股。三大法人合計買超2,597萬股。</li><li><strong>外資動向</strong>：連續3日買超(5/7-5/11)，買超張數從1,195萬→170萬→855萬。外資明顯看好文曄長期價值。</li><li><strong>千張大戶變化</strong>：從74人(79.88%, 2025/1)增至121人(84.29%, 2026/5)。大戶持續增持，籌碼集中。</li><li><strong>診斷見解</strong>：外資與投信同步買超形成「方向性合力」，配合大戶持股比例持續上升，為明確的籌碼收集訊號。</li></ul><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="_1-法人買超分析" tabindex="-1">1. 法人買超分析 <a class="header-anchor" href="#_1-法人買超分析" aria-label="Permalink to &quot;1. 法人買超分析&quot;">​</a></h3><ul><li><strong>外資強勢布局</strong>：近4日累計買超2,219萬股(佔總股數1.75%)。5/7單日買超1,195萬股為近期最大量。外資看好(1)AI需求帶動營收成長(2)FE併購後全球龍頭地位(3)估值合理(PER~15-18倍)。</li><li><strong>投信同步加碼</strong>：近4日累計買超348萬股。投信通常為中長期布局，連續買超代表對基本面有信心。</li><li><strong>自營商小幅買超</strong>：+30萬股，影響有限。自營商通常為短線操作。</li></ul><h3 id="_2-籌碼集中度" tabindex="-1">2. 籌碼集中度 <a class="header-anchor" href="#_2-籌碼集中度" aria-label="Permalink to &quot;2. 籌碼集中度&quot;">​</a></h3><ul><li><strong>千張大戶84.3%</strong>：121人持有84.29%股權，為極高水準。大戶持續增持(從74人→121人)，代表大資金看好。</li><li><strong>散戶持股&lt;1%</strong>：1-5張散戶持不到1%股權，賣壓有限。股價波動主要由大戶與法人決定。</li><li><strong>流通籌碼稀少</strong>：大戶+外資合計&gt;100%(含重複計算)，市場流通籌碼極少。若法人持續買超，可能觸發軋空行情。</li></ul><h3 id="_3-動能判定" tabindex="-1">3. 動能判定 <a class="header-anchor" href="#_3-動能判定" aria-label="Permalink to &quot;3. 動能判定&quot;">​</a></h3><ul><li><strong>法人共識性買盤</strong>：外資+投信同步買超形成「方向性合力」，非分歧狀態。代表機構投資人對文曄基本面有共識。</li><li><strong>無派發跡象</strong>：千張大戶比例從79.88%升至84.29%，散戶人數未暴增。無「大戶出貨給散戶」之派發特徵。</li><li><strong>股價支撐</strong>：法人買超+籌碼集中=強勁下檔支撐。若股價回檔，法人可能加碼護盤。</li></ul><h2 id="💡-專家評析-多空雙向分析" tabindex="-1">💡 專家評析（多空雙向分析） <a class="header-anchor" href="#💡-專家評析-多空雙向分析" aria-label="Permalink to &quot;💡 專家評析（多空雙向分析）&quot;">​</a></h2><h3 id="🔴-空方觀點-利空風險" tabindex="-1">🔴 空方觀點（利空風險） <a class="header-anchor" href="#🔴-空方觀點-利空風險" aria-label="Permalink to &quot;🔴 空方觀點（利空風險）&quot;">​</a></h3><ol><li><strong>外資買超可能為短線套利</strong>：外資近期買超可能為AI題材之短線布局，非長線持有。若AI需求不如預期，外資可能快速撤出，造成股價壓力。</li><li><strong>籌碼過度集中風險</strong>：84.3%集中於大戶，若大戶同步賣壓(如因併購整合不如預期)，股價可能劇烈波動。流動性風險為主要 Concern。</li></ol><h3 id="🟢-多方觀點-機會可能性" tabindex="-1">🟢 多方觀點（機會可能性） <a class="header-anchor" href="#🟢-多方觀點-機會可能性" aria-label="Permalink to &quot;🟢 多方觀點（機會可能性）&quot;">​</a></h3><ol><li><strong>法人共識性買盤為強烈訊號</strong>：外資+投信同步買超代表機構投資人對文曄基本面有共識。此為股價上漲之重要驅動力。</li><li><strong>大戶持續增持=下檔支撐強</strong>：千張大戶從74人增至121人(+64%)，持股比例+4.41pp。大戶有信心增持，股價回檔時有強勁支撐。</li></ol><h3 id="⚖️-綜合權衡" tabindex="-1">⚖️ 綜合權衡 <a class="header-anchor" href="#⚖️-綜合權衡" aria-label="Permalink to &quot;⚖️ 綜合權衡&quot;">​</a></h3><p>法人共識性買超+籌碼持續集中為正面訊號。外資強勢布局反映對AI需求與全球龍頭地位之信心。需關注外資是否為短線操作。</p><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li><strong>原始數據</strong>：FinMind TaiwanStockInstitutionalHolding + TaiwanStockShareholdingSpread</li><li><strong>查詢參數</strong>：stock_id=3036, start=2025-01-01, end=2026-05-12</li><li><strong>數據查詢日期</strong>：2026-05-12</li></ul>',24)])])}const c=t(i,[["render",n]]);export{u as __pageData,c as default};
